  2→ * ProjectRepository - CRUD operations for Project model
  3→ *
  4→ * Provides typed methods for Project queries with soft-delete support.
  5→ * Handles Project stage transitions and member management.
  6→ */
  7→
  8→import { prisma } from './prisma';
  9→import type {
 10→  Deal,
 11→  Project,
 12→  ProjectMember,
 13→  ProjectStage,
 14→  Prisma,
 15→} from '@prisma/client';
 16→import { randomUUID } from 'node:crypto';
 17→
 18→/**
 19→ * Project creation input type
 20→ */
 21→export type ProjectCreateInput = Omit<Prisma.ProjectUncheckedCreateInput, 'id' | 'createdAt' | 'updatedAt'>;
 22→
 23→/**
 24→ * Project update input type
 25→ */
 26→export type ProjectUpdateInput = Prisma.ProjectUncheckedUpdateInput;
 27→
 28→/**
 29→ * Project findMany params type
 30→ */
 31→export type ProjectFindManyParams = {
 32→  where?: Prisma.ProjectWhereInput;
 33→  orderBy?: Prisma.ProjectOrderByWithRelationInput;
 34→  skip?: number;
 35→  take?: number;
 36→  include?: Prisma.ProjectInclude;
 37→};
 38→
 39→/**
 40→ * Repository for Project CRUD operations
 41→ */
 42→export class ProjectRepository {
 43→  /**
 44→   * Find many projects with optional filtering
 45→   * Automatically filters out soft-deleted records
 46→   */
 47→  async findMany(params?: ProjectFindManyParams): Promise<Project[]> {
 48→    const { where, ...rest } = params ?? {};
 49→
 50→    return prisma.project.findMany({
 51→      ...rest,
 52→      where: {
 53→        ...where,
 54→        deletedAt: null, // Always exclude soft-deleted
 55→      },
 56→    });
 57→  }
 58→
 59→  /**
 60→   * Find a single project by ID
 61→   * Returns null if not found or soft-deleted
 62→   */
 63→  async findUnique(
 64→    id: string,
 65→    include?: Prisma.ProjectInclude
 66→  ): Promise<Project | null> {
 67→    return prisma.project.findFirst({
 68→      where: { id, deletedAt: null },
 69→      include,
 70→    });
 71→  }
 72→
 73→  /**
 74→   * Find projects by status
 75→   */
 76→  async findByStatus(status: string): Promise<Project[]> {
 77→    return this.findMany({
 78→      where: { status },
 79→      orderBy: { createdAt: 'desc' },
 80→    });
 81→  }
 82→
 83→  /**
 84→   * Find projects by manager (owner)
 85→   */
 86→  async findByManager(managerId: string): Promise<Project[]> {
 87→    return this.findMany({
 88→      where: { managerId },
 89→      orderBy: { createdAt: 'desc' },
 90→    });
 91→  }
 92→
 93→  /**
 94→   * Find projects by contact
 95→   */
 96→  async findByContact(contactId: string): Promise<Project[]> {
 97→    return this.findMany({
 98→      where: { contactId },
 99→      orderBy: { createdAt: 'desc' },
100→    });
101→  }
102→
103→  /**
104→   * Find projects by deal
105→   */
106→  async findByDeal(dealId: string): Promise<Project[]> {
107→    return this.findMany({
108→      where: { dealId },
109→      orderBy: { createdAt: 'desc' },
110→    });
111→  }
112→
113→  /**
114→   * Create a new project
115→   * Generates UUID and timestamps if not provided
116→   */
117→  async create(data: ProjectCreateInput): Promise<Project> {
118→    const now = new Date();
119→
120→    return prisma.project.create({
121→      data: {
122→        ...data,
123→        id: data.id ?? randomUUID(),
124→        externalNumber: data.externalNumber ?? this.generateExternalNumber(),
125→        createdAt: data.createdAt ?? now,
126→        updatedAt: data.updatedAt ?? now,
127→      },
128→    });
129→  }
130→
131→  /**
132→   * Generate external project number in format PRJ-YYYY-NNNNN
133→   */
134→  private generateExternalNumber(): string {
135→    const year = new Date().getFullYear();
136→    const random = Math.floor(Math.random() * 99999).toString().padStart(5, '0');
137→    return `PRJ-${year}-${random}`;
138→  }
139→
140→  /**
141→   * Update an existing project
142→   * Throws Error if project doesn't exist or is soft-deleted
143→   */
144→  async update(
145→    id: string,
146→    data: ProjectUpdateInput
147→  ): Promise<Project> {
148→    // Verify project exists and not deleted
149→    const existing = await this.findUnique(id);
150→    if (!existing) {
151→      throw new Error(`Project with id ${id} not found`);
152→    }
153→
154→    return prisma.project.update({
155→      where: { id },
156→      data: {
157→        ...data,
158→        updatedAt: new Date(),
159→      },
160→    });
161→  }
162→
163→  /**
164→   * Soft delete a project by setting deletedAt timestamp
165→   * Does NOT actually delete the record from database
166→   */
167→  async softDelete(id: string): Promise<Project> {
168→    // Verify project exists and not already deleted
169→    const existing = await this.findUnique(id);
170→    if (!existing) {
171→      throw new Error(`Project with id ${id} not found`);
172→    }
173→
174→    return prisma.project.update({
175→      where: { id },
176→      data: { deletedAt: new Date() },
177→    });
178→  }
179→
180→  /**
181→   * Count projects matching criteria (excluding soft-deleted)
182→   */
183→  async count(where?: Prisma.ProjectWhereInput): Promise<number> {
184→    return prisma.project.count({
185→      where: {
186→        ...where,
187→        deletedAt: null,
188→      },
189→    });
190→  }
191→
192→  /**
193→   * Create a project stage
194→   */
195→  async createStage(
196→    projectId: string,
197→    data: Omit<Prisma.ProjectStageUncheckedCreateInput, 'id' | 'projectId'>
198→  ): Promise<ProjectStage> {
199→    return prisma.projectStage.create({
200→      data: {
201→        ...data,
202→        id: randomUUID(),
203→        projectId,
204→      },
205→    });
206→  }
207→
208→  /**
209→   * Update a project stage
210→   */
211→  async updateStage(
212→    stageId: string,
213→    data: Prisma.ProjectStageUncheckedUpdateInput
214→  ): Promise<ProjectStage> {
215→    return prisma.projectStage.update({
216→      where: { id: stageId },
217→      data,
218→    });
219→  }
220→
221→  /**
222→   * Find stages for a project
223→   */
224→  async findStages(projectId: string): Promise<ProjectStage[]> {
225→    return prisma.projectStage.findMany({
226→      where: { projectId },
227→      orderBy: { order: 'asc' },
228→    });
229→  }
230→
231→  /**
232→   * Add a member to a project
233→   */
234→  async addMember(
235→    projectId: string,
236→    userId: string,
237→    role: string = 'member'
238→  ): Promise<ProjectMember> {
239→    return prisma.projectMember.create({
240→      data: {
241→        id: randomUUID(),
242→        projectId,
243→        userId,
244→        role,
245→        joinedAt: new Date(),
246→      },
247→    });
248→  }
249→
250→  /**
251→   * Remove a member from a project (sets leftAt timestamp)
252→   */
253→  async removeMember(projectId: string, userId: string): Promise<ProjectMember> {
254→    const member = await prisma.projectMember.findUnique({
255→      where: { projectId_userId: { projectId, userId } },
256→    });
257→
258→    if (!member) {
259→      throw new Error(`Member ${userId} not found in project ${projectId}`);
260→    }
261→
262→    return prisma.projectMember.update({
263→      where: { projectId_userId: { projectId, userId } },
264→      data: { leftAt: new Date() },
265→    });
266→  }
267→
268→  /**
269→   * Find members for a project
270→   */
271→  async findMembers(projectId: string): Promise<ProjectMember[]> {
272→    return prisma.projectMember.findMany({
273→      where: {
274→        projectId,
275→        leftAt: null, // Only active members
276→      },
277→      include: {
278→        User: {
279→          select: {
280→            id: true,
281→            name: true,
282→            email: true,
283→          },
284→        },
285→      },
286→    });
287→  }
288→
289→  /**
290→   * Complete a project and cascade the completion to the related Deal.
291→   * Validates all project stages are completed first.
292→   * Uses Prisma transaction to atomically update both Project and Deal.
293→   *
294→   * @param projectId - The project ID to complete
295→   * @param userId - The user ID performing the completion (for DealHistory)
296→   * @returns Object containing updated Project and Deal (if exists)
297→   * @throws Error if project not found, stages not completed, or deal won stage not found
298→   */
299→  async completeWithCascade(
300→    projectId: string,
301→    userId: string
302→  ): Promise<{ project: Project; deal: Deal | null }> {
303→    const now = new Date();
304→
305→    // Use transaction to ensure atomic updates
306→    return prisma.$transaction(async (tx) => {
307→      // 1. Fetch project with stages to validate completion
308→      const project = await tx.project.findFirst({
309→        where: { id: projectId, deletedAt: null },
310→        include: {
311→          ProjectStage: {
312→            orderBy: { order: 'asc' },
313→          },
314→        },
315→      });
316→
317→      if (!project) {
318→        throw new Error(`Project with id ${projectId} not found`);
319→      }
320→
321→      // 2. Validate all stages are completed
322→      const incompleteStages = project.ProjectStage.filter(
323→        (stage) => stage.status !== 'completed'
324→      );
325→      if (incompleteStages.length > 0) {
326→        const stageNames = incompleteStages.map((s) => s.name).join(', ');
327→        throw new Error(
328→          `Cannot complete project: incomplete stages: ${stageNames}`
329→        );
330→      }
331→
332→      // 3. Find the won stage for the deal's pipeline
333→      let wonStageId: string | null = null;
334→      let deal: Deal | null = null;
335→
336→      if (project.dealId) {
337→        // Fetch the deal to get its pipeline
338→        const existingDeal = await tx.deal.findFirst({
339→          where: { id: project.dealId, deletedAt: null },
340→          include: { DealStage: true },
341→        });
342→
343→        if (!existingDeal) {
344→          throw new Error(`Deal with id ${project.dealId} not found`);
345→        }
346→
347→        // Find the won stage in the same pipeline
348→        const wonStage = await tx.dealStage.findFirst({
349→          where: {
350→            pipelineId: existingDeal.pipelineId,
351→            isWonStage: true,
352→          },
353→        });
354→
355→        if (!wonStage) {
356→          throw new Error(
357→            `No won stage found in pipeline ${existingDeal.pipelineId}`
358→          );
359→        }
360→
361→        wonStageId = wonStage.id;
362→        deal = existingDeal;
363→      }
364→
365→      // 4. Update project status to completed
366→      const updatedProject = await tx.project.update({
367→        where: { id: projectId },
368→        data: {
369→          status: 'completed',
370→          completedAt: now,
371→          updatedAt: now,
372→        },
373→      });
374→
375→      // 5. If deal exists, move it to won stage and set closedAt
376→      let updatedDeal: Deal | null = null;
377→      if (deal && wonStageId) {
378→        const fromStageId = deal.stageId;
379→
380→        // Record deal history for the stage move
381→        await tx.dealHistory.create({
382→          data: {
383→            id: randomUUID(),
384→            dealId: deal.id,
385→            fromStageId,
386→            toStageId: wonStageId,
387→            changedBy: userId,
388→            changedAt: now,
389→          },
390→        });
391→
392→        // Update deal to won stage and set closed timestamps
393→        updatedDeal = await tx.deal.update({
394→          where: { id: deal.id },
395→          data: {
396→            stageId: wonStageId,
397→            actualCloseDate: now,
398→            closedAt: now,
399→            updatedAt: now,
400→          },
401→        });
402→      }
403→
404→      return {
405→        project: updatedProject,
406→        deal: updatedDeal,
407→      };
408→    });
409→  }
410→}
